int naive(char *T, int n, char *P, int m) {
  for (int i = 0; i < n - m + 1; ++i) {
    bool found = true;
    for (int k = 0; k < m; ++k) {
      if (P[k] != T[i + k]) {
        found = false;
        break;
      }
    }
    if (found) return i;
  }
  return -1;
}

int kmp(char *T, int n, char *P, int m, int *F) {
  int i = 0, j = 0;
  while (i < n) {
    if (j == -1 || T[i] == P[j]) {
      i++; j++;
      if (j == m)
        return i - m;  // match found
    } else {
      j = F[j];        // fall back using failure function
    }
  }
  return -1;
}
// Time: O(n) -- each character of T examined at most twice

void computeF(char *P, int m, int *F) {
  int i = 0, j = -1;
  F[0] = -1;
  while (i < m - 1) {
    if (j == -1 || P[i] == P[j]) {
      i++; j++;
      F[i] = j;
    } else {
      j = F[j];
    }
  }
}
// Time: O(m)
